mapper.select:
SELECT M.MATERIAL_ID AS materialId, M.MATERIAL_NAME AS materialName, M.COST_PRICE AS costPrice,
/* 점포 재고 (없으면 0) */ NVL(I.CURRENT_QUANTITY, 0) AS currentQuantity,
/* 구매가격 */ (M.COST_PRICE * NVL(I.CURRENT_QUANTITY, 0)) AS buyPrice,
/* ===================================== 상태 = 본사 기준 + 판매 가능 여부만 ===================================== */ CASE WHEN M.STATUS = 'ACTIVE' THEN '판매중' ELSE '판매중지' END AS status
FROM MATERIALS M
/* 재고가 없어도 무조건 보여야 하므로 LEFT JOIN */ LEFT JOIN STORE_INVENTORIES I ON M.MATERIAL_ID = I.MATERIAL_ID AND I.STORE_ID = #{storeId}
/* 본사 기준으로 전체 자재 표시 */ WHERE 1=1
ORDER BY M.MATERIAL_NAME
